import type { KyokuyaSudokuContextData } from './state'

export enum KyokuyaSudokuActionsType {
  // Restart game.
  RESTART = '@kyokuya/sudoku/restart',

  // Reset game.
  RESET = '@kyokuya/sudoku/reset',

  // Start game.
  START = '@kyokuya/sudoku/start',

  // Pause game.
  PAUSE = '@kyokuya/sudoku/pause',

  // Resume game.
  RESUME = '@kyokuya/sudoku/resume',

  // Game finished.
  FINISHED = '@kyokuya/sudoku/finished',

  // CHANGE the activated board cell.
  ACTIVE = '@kyokuya/sudoku/active',

  // Asking for a hint.
  HINT = '@kyokuya/sudoku/hint',

  // Input into a board cell.
  INPUT = '@kyokuya/sudoku/input',
}

export type KyokuyaSudokuAction =
  | {
      type: KyokuyaSudokuActionsType.RESTART
    }
  | {
      type: KyokuyaSudokuActionsType.RESET
      payload: {
        difficulty?: KyokuyaSudokuContextData['difficulty']
        SUDOKU_SIZE_SQRT?: KyokuyaSudokuContextData['SUDOKU_SIZE_SQRT']
        radix?: KyokuyaSudokuContextData['radix']
      }
    }
  | {
      type: KyokuyaSudokuActionsType.START
    }
  | {
      type: KyokuyaSudokuActionsType.PAUSE
    }
  | {
      type: KyokuyaSudokuActionsType.RESUME
    }
  | {
      type: KyokuyaSudokuActionsType.FINISHED
      payload: number // score
    }
  | {
      type: KyokuyaSudokuActionsType.ACTIVE
      payload: { r: number; c: number }
    }
  | {
      type: KyokuyaSudokuActionsType.HINT
    }
  | {
      type: KyokuyaSudokuActionsType.INPUT
      payload: number
    }
