import { createLocalStoreStorage } from '@kyokuya/react-storage'
import type { KyokuyaSudokuContextData } from '@kyokuya/react-sudoku'
import {
  KyokuyaSudokuContext,
  initKyokuyaSudokuContextData,
  kyokuyaSudokuContextReducer,
} from '@kyokuya/react-sudoku'
import PropTypes from 'prop-types'
import React, { useMemo, useReducer } from 'react'
import KyokuyaSudokuGameMain from './SudokuGameMain'
import useKyokuyaSudokuContextDataEffect from './useKyokuyaSudokuContextDataEffect'

export const KyokuyaSudokuGame: React.FC<{
  storageKey?: string
  initialContextData?: Partial<KyokuyaSudokuContextData>
}> = props => {
  const { storageKey, initialContextData } = props

  const storage = useMemo(
    () =>
      storageKey
        ? createLocalStoreStorage<Partial<KyokuyaSudokuContextData>>(
            storageKey,
            JSON,
          )
        : null,
    [storageKey],
  )

  const [contextData, dispatch] = useReducer(
    kyokuyaSudokuContextReducer,
    () => ({
      ...(storage == null ? {} : storage.load()),
      ...initialContextData,
    }),
    initKyokuyaSudokuContextData,
  )

  useKyokuyaSudokuContextDataEffect(storage, contextData)

  return (
    <KyokuyaSudokuContext.Provider value={{ ...contextData, dispatch }}>
      <KyokuyaSudokuGameMain />
    </KyokuyaSudokuContext.Provider>
  )
}

KyokuyaSudokuGame.propTypes = {
  storageKey: PropTypes.string,
  initialContextData: PropTypes.any,
}

KyokuyaSudokuGame.displayName = 'KyokuyaSudokuGame'
export default KyokuyaSudokuGame
