import { KyokuyaSudokuContext } from '@kyokuya/react-sudoku'
import {
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  TextField,
} from '@material-ui/core'
import React, { useContext, useEffect, useState } from 'react'

export interface KyokuyaSudokuGameInputProps {
  /**
   * Dialog container element
   */
  container?: HTMLElement | null
  /**
   * Initial value.
   */
  initialValue: string
  /**
   * Whether to show the dialog.
   */
  visible: boolean
  /**
   * Input label.
   */
  label?: string
  /**
   * Triggered on canceled.
   */
  onCancel(): void
  /**
   * Triggered on confirmed.
   * @param value
   */
  onConfirm(value: string): void
}

export function KyokuyaSudokuGameInput(
  props: KyokuyaSudokuGameInputProps,
): React.ReactElement {
  const { radix } = useContext(KyokuyaSudokuContext)

  const { container, initialValue, visible, label, onCancel, onConfirm } = props
  const [value, setValue] = useState<string>(initialValue)
  useEffect(() => setValue(initialValue), [initialValue, visible])

  return (
    <Dialog
      container={container}
      open={visible}
      onClose={onCancel}
      aria-labelledby="sudoku-input-dialog"
    >
      <DialogContent>
        <TextField
          autoFocus={true}
          margin="dense"
          label={label}
          type={radix <= 10 ? 'number' : 'input'}
          fullWidth={true}
          value={value}
          onChange={e => setValue(e.target.value)}
          onFocus={e => e.target.select()}
          onKeyDown={e => {
            if (e.key === 'Enter') onConfirm(value)
          }}
        />
      </DialogContent>
      <DialogActions>
        <Button color="default" onClick={onCancel}>
          Cancel
        </Button>
        <Button color="primary" onClick={() => onConfirm(value)}>
          Confirm
        </Button>
      </DialogActions>
    </Dialog>
  )
}

KyokuyaSudokuGameInput.displayName = 'KyokuyaSudokuGameInput'
export default KyokuyaSudokuGameInput
