import PropTypes from 'prop-types'
import React, { useReducer } from 'react'
import { KyokuyaSudokuContext } from './context'
import kyokuyaSudokuContextReducer from './reducer'
import type { KyokuyaSudokuContextData } from './state'
import { initKyokuyaSudokuContextData } from './state'

export interface KyokuyaSudokuContextProviderProps {
  /**
   * Initial context data.
   */
  initialContextData?: Partial<KyokuyaSudokuContextData>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const KyokuyaSudokuContextProvider: React.FC<KyokuyaSudokuContextProviderProps> =
  props => {
    const { children, initialContextData } = props
    const [contextData, dispatch] = useReducer(
      kyokuyaSudokuContextReducer,
      () => ({ ...initialContextData }),
      initKyokuyaSudokuContextData,
    )

    return (
      <KyokuyaSudokuContext.Provider value={{ ...contextData, dispatch }}>
        {children}
      </KyokuyaSudokuContext.Provider>
    )
  }

KyokuyaSudokuContextProvider.propTypes = {
  initialContextData: PropTypes.any,
  children: PropTypes.node.isRequired,
}

KyokuyaSudokuContextProvider.displayName = 'KyokuyaSudokuContextProvider'
export default KyokuyaSudokuContextProvider
