import { useState } from 'react'
import type { GameRunningStatus } from '../types'

/**
 * Time usage record.
 */
interface RecordTime {
  /**
   * Cumulative use of time.
   */
  usedTime: number
  /**
   * Timestamp of the last time the timer started.
   */
  lastStartTime: number
}

/**
 * Return elapsed time (milliseconds) in game.
 * @param gameStatus
 * @returns
 */
export function useElapsedTime(gameStatus: GameRunningStatus): number {
  const [{ usedTime, lastStartTime }, setRecordTime] = useState<RecordTime>({
    usedTime: 0,
    lastStartTime: -1,
  })

  switch (gameStatus) {
    case 'pending': {
      if (usedTime !== 0 || lastStartTime !== -1) {
        setRecordTime({ usedTime: 0, lastStartTime: -1 })
      }
      return 0
    }
    case 'running': {
      if (lastStartTime === -1) {
        setRecordTime({ usedTime, lastStartTime: Date.now() })
        return usedTime
      }
      return usedTime + Date.now() - lastStartTime
    }
    case 'paused': {
      if (lastStartTime !== -1) {
        const nextUsedTime = usedTime + Date.now() - lastStartTime
        setRecordTime({ usedTime: nextUsedTime, lastStartTime: -1 })
        return nextUsedTime
      }
      return usedTime
    }
    case 'finished': {
      if (lastStartTime !== -1) {
        const nextUsedTime = usedTime + Date.now() - lastStartTime
        setRecordTime({ usedTime: nextUsedTime, lastStartTime: -1 })
        return nextUsedTime
      }
      return usedTime
    }
    default:
      throw new TypeError(
        `[usedRecordTime] expect a GameRunningState, but got (${gameStatus})`,
      )
  }
}
